/* ═══════════════════════════════════════════
   TERMINAL SNIPPET (typing effect)
   ═══════════════════════════════════════════ */
function TerminalSnippet({ project }: { project: Project }) {
  const lines = useMemo(() => {
    if (project.title === 'EchoScore') {
      return [
        '$ python -m echoscore.pipeline --mode audit',
        '> Loading Whisper model... done',
        '> RAG context retrieval via Milvus... 23 chunks',
        '> LLM scoring: compliance=94% quality=87%',
        '> Dashboard sync complete. Report exported.',
      ];
    }
    return [
      `$ flask run --host=0.0.0.0`,
      `> Fetching weather for current location...`,
      `> Condition: Rainy | Temp: 22°C | Mood: Chill`,
      `> Generating playlist via YouTube API...`,
      `> 12 tracks matched. Serving recommendations.`,
    ];
  }, [project.title]);

  const [typed, setTyped] = useState('');
  const fullText = lines.join('\n');

  useEffect(() => {
    let i = 0;
    let timeout: ReturnType<typeof setTimeout>;
    const type = () => {
      if (i <= fullText.length) {
        setTyped(fullText.slice(0, i));
        const nextChar = fullText[i];
        const delay = nextChar === '\n' ? 120 : 18;
        i++;
        timeout = setTimeout(type, delay);
      }
    };
    timeout = setTimeout(type, 500);
    return () => clearTimeout(timeout);
  }, [fullText]);

  return (
    <div className="terminal-card rounded-none rounded-t-[16px] border-0 border-b border-border">
      <div className="terminal-header">
        <span className="terminal-dot bg-[#ff5f57]" />
        <span className="terminal-dot bg-[#ffbd2e]" />
        <span className="terminal-dot bg-[#28c840]" />
        <span className="text-[11px] text-text-dim ml-2 font-mono">
          ~/{project.title.toLowerCase().replace(/\s+/g, '-')}
        </span>
      </div>
      <div className="p-4 min-h-[140px]">
        <pre className="text-[12px] leading-relaxed text-text-muted font-mono whitespace-pre-wrap">
          {typed.split('\n').map((line, i) => (
            <div key={i} className="min-h-[1.4rem]">
              {line.startsWith('$') ? (
                <>
                  <span className="text-green">$ </span>
                  <span className="text-text font-medium">{line.slice(2)}</span>
                </>
              ) : line.startsWith('>') ? (
                <>
                  <span className="text-text-dim">{'  '}</span>
                  <span className="text-text-muted">{line.slice(2)}</span>
                </>
              ) : (
                <span className="text-text-muted">{line}</span>
              )}
            </div>
          ))}
          <span className="inline-block w-2 h-4 bg-accent/70 animate-pulse ml-0.5" />
        </pre>
      </div>
      {/* Carousel dots */}
      <div className="flex justify-center gap-1.5 pb-3">
        <span className="w-1.5 h-1.5 rounded-full bg-text-dim" />
        <span className="w-1.5 h-1.5 rounded-full bg-accent" />
      </div>
    </div>
  );
}

