'use client';

import { useEffect, useRef } from 'react';
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import { EXPERIENCES } from '@/lib/constants';
import { ScrollReveal, TextMaskReveal } from '@/components/shared/ScrollReveal';

gsap.registerPlugin(ScrollTrigger);

export function Experience() {
  const lineRef = useRef<SVGLineElement>(null);
  const sectionRef = useRef<HTMLDivElement>(null);

  // SVG line draw animation
  useEffect(() => {
    if (!lineRef.current || !sectionRef.current) return;

    const line = lineRef.current;
    const length = line.getTotalLength();
    line.style.strokeDasharray = `${length}`;
    line.style.strokeDashoffset = `${length}`;

    const ctx = gsap.context(() => {
      gsap.to(line, {
        strokeDashoffset: 0,
        ease: 'none',
        scrollTrigger: {
          trigger: sectionRef.current,
          start: 'top 60%',
          end: 'bottom 30%',
          scrub: 1,
        },
      });
    }, sectionRef);

    return () => ctx.revert();
  }, []);

  return (
    <section ref={sectionRef} id="experience" className="relative z-10 py-24 md:py-32">
      <div className="section-container">
        {/* Header */}
        <ScrollReveal variant="fade-up" className="mb-4">
          <span className="text-xs font-mono text-accent tracking-widest uppercase">
            Experience
          </span>
        </ScrollReveal>
        <TextMaskReveal className="mb-16 md:mb-20">
          <h2 className="text-4xl sm:text-5xl font-bold text-text leading-tight">
            My Journey
          </h2>
        </TextMaskReveal>

        {/* Timeline */}
        <div className="relative max-w-4xl mx-auto">
          {/* SVG timeline line */}
          <svg
            className="absolute left-4 md:left-8 top-0 bottom-0 w-px h-full"
            style={{ overflow: 'visible' }}
          >
            <line
              ref={lineRef}
              x1="0"
              y1="0"
              x2="0"
              y2="100%"
              stroke="#6366F1"
              strokeWidth="1"
            />
          </svg>

          {/* Cards */}
          <div className="flex flex-col gap-14 md:gap-18">
            {EXPERIENCES.map((exp, i) => (
              <ScrollReveal key={exp.role} variant="fade-right" delay={i * 0.08}>
                <div className="relative pl-12 md:pl-20">
                  {/* Dot */}
                  <div
                    className="absolute left-4 md:left-8 top-2 w-3 h-3 rounded-full bg-accent -translate-x-1/2 z-10"
                    style={exp.current ? { animation: 'pulse-glow 3s infinite' } : {}}
                  />

                  {/* Card */}
                  <div
                    className={`glass p-6 md:p-8 transition-all duration-300 hover:-translate-y-1 ${
                      exp.current ? 'border-accent/30' : ''
                    }`}
                    style={exp.current ? { boxShadow: '0 0 0 1px rgba(99,102,241,0.2)' } : {}}
                  >
                    <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2 mb-3">
                      <h3 className="text-lg font-bold text-text">
                        {exp.role}
                      </h3>
                      <span className="text-xs font-mono text-accent bg-accent-dim px-3 py-1 rounded-full whitespace-nowrap">
                        {exp.period}
                      </span>
                    </div>
                    <p className="text-sm font-medium text-accent-bright mb-3">
                      {exp.company}
                    </p>
                    <p className="text-sm text-text-muted leading-relaxed mb-4">
                      {exp.description}
                    </p>
                    <ul className="space-y-2 mb-4">
                      {exp.highlights.map((h) => (
                        <li key={h} className="text-sm text-text-muted flex gap-2">
                          <span className="text-accent mt-0.5 shrink-0">▹</span>
                          {h}
                        </li>
                      ))}
                    </ul>
                    <div className="flex flex-wrap gap-2">
                      {exp.tech.map((t) => (
                        <span
                          key={t}
                          className="px-2.5 py-0.5 text-[11px] font-mono text-text-muted rounded-full border border-border"
                        >
                          {t}
                        </span>
                      ))}
                    </div>
                  </div>
                </div>
              </ScrollReveal>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
