'use client';

import { useState } from 'react';
import { motion } from 'framer-motion';
import { FiGithub, FiLinkedin, FiTwitter, FiMail } from 'react-icons/fi';
import { LINKS, MAIL_TO } from '@/lib/constants';
import { TextMaskReveal, ScrollReveal } from '@/components/shared/ScrollReveal';
import { staggerSlow, scaleIn } from '@/lib/animations';

export function Contact() {
  const [copied, setCopied] = useState(false);

  const copyEmail = async () => {
    try {
      await navigator.clipboard.writeText(LINKS.email);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch {
      const el = document.createElement('textarea');
      el.value = LINKS.email;
      document.body.appendChild(el);
      el.select();
      document.execCommand('copy');
      document.body.removeChild(el);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }
  };

  const socials = [
    { icon: FiGithub, href: LINKS.githubProfile, label: 'GitHub' },
    { icon: FiLinkedin, href: LINKS.linkedin, label: 'LinkedIn' },
    { icon: FiTwitter, href: LINKS.x, label: 'Twitter' },
    { icon: FiMail, href: MAIL_TO, label: 'Email' },
  ];

  return (
    <section id="contact" className="relative z-10 min-h-screen flex items-center justify-center py-24 md:py-32 overflow-hidden">
      {/* Animated gradient mesh background */}
      <div
        className="absolute inset-0 opacity-20"
        style={{
          background: 'radial-gradient(ellipse at 30% 50%, rgba(99,102,241,0.12) 0%, transparent 60%), radial-gradient(ellipse at 70% 50%, rgba(99,102,241,0.08) 0%, transparent 60%)',
          backgroundSize: '200% 200%',
          animation: 'gradient-mesh 8s ease infinite',
        }}
      />

      <div className="section-container relative text-center">
        {/* Heading */}
        <TextMaskReveal className="mb-4" delay={0}>
          <h2 className="text-5xl sm:text-6xl md:text-[80px] font-bold text-text leading-none">
            LET&apos;S BUILD
          </h2>
        </TextMaskReveal>
        <TextMaskReveal delay={0.12}>
          <h2 className="text-5xl sm:text-6xl md:text-[80px] font-bold leading-none">
            <span className="gradient-text-accent">SOMETHING</span>
          </h2>
        </TextMaskReveal>

        {/* Subtitle */}
        <ScrollReveal variant="fade-up" delay={0.3} className="mt-8 mb-12">
          <p className="text-lg text-text-muted max-w-md mx-auto">
            Got a project in mind? Let&apos;s bring it to life together.
          </p>
        </ScrollReveal>

        {/* Email */}
        <ScrollReveal variant="fade-up" delay={0.4} className="mb-12">
          <button
            onClick={copyEmail}
            className="group relative inline-block"
            data-cursor="interactive"
          >
            <span className="font-mono text-xl sm:text-2xl md:text-[28px] text-text hover:text-accent transition-colors duration-200">
              {LINKS.email}
            </span>
            <span className="absolute -bottom-1 left-0 w-full h-px bg-accent origin-left transform scale-x-0 group-hover:scale-x-100 transition-transform duration-300" style={{ transitionTimingFunction: 'cubic-bezier(0.16, 1, 0.3, 1)' }} />
          </button>

          {/* Toast */}
          <motion.div
            initial={false}
            animate={{ opacity: copied ? 1 : 0, y: copied ? 0 : 10 }}
            className="mt-4 text-sm font-mono text-accent"
          >
            Copied ✓
          </motion.div>
        </ScrollReveal>

        {/* Social links */}
        <motion.div
          variants={staggerSlow}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true }}
          className="flex items-center justify-center gap-4"
        >
          {socials.map((s) => (
            <motion.a
              key={s.label}
              variants={scaleIn}
              href={s.href}
              target={s.label === 'Email' ? undefined : '_blank'}
              rel={s.label === 'Email' ? undefined : 'noopener noreferrer'}
              aria-label={s.label}
              className="w-11 h-11 rounded-lg border border-border flex items-center justify-center text-text-muted hover:text-accent hover:border-accent/40 transition-all duration-300 hover:scale-110"
              data-cursor="interactive"
            >
              <s.icon className="w-4 h-4" />
            </motion.a>
          ))}
        </motion.div>
      </div>
    </section>
  );
}
